const defaultData = {
  cpu: '--',
  ram: '--',
  players: 0,
  status: 'offline',
  time: '--',
  ready: false,
};

let latestData = null;

function setCorsHeaders(res) {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET,POST,OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  res.setHeader('Cache-Control', 'no-store, max-age=0');
}

function normalizeStatus(value) {
  return String(value || 'offline').trim().toLowerCase() === 'online' ? 'online' : 'offline';
}

function normalizePayload(payload = {}) {
  const players = Number.parseInt(payload.players, 10);

  return {
    cpu: typeof payload.cpu === 'string' && payload.cpu.trim() ? payload.cpu.trim() : defaultData.cpu,
    ram: typeof payload.ram === 'string' && payload.ram.trim() ? payload.ram.trim() : defaultData.ram,
    players: Number.isFinite(players) && players >= 0 ? players : defaultData.players,
    status: normalizeStatus(payload.status),
    time: typeof payload.time === 'string' && payload.time.trim() ? payload.time.trim() : defaultData.time,
    ready: true,
  };
}

function currentData() {
  return latestData ? { ...latestData } : { ...defaultData };
}

module.exports = async (req, res) => {
  setCorsHeaders(res);

  if (req.method === 'OPTIONS') {
    return res.status(204).end();
  }

  if (req.method === 'GET') {
    return res.status(200).json(currentData());
  }

  if (req.method === 'POST') {
    try {
      const body = typeof req.body === 'string' ? JSON.parse(req.body || '{}') : (req.body || {});
      latestData = normalizePayload(body);

      return res.status(200).json({
        success: true,
        data: currentData(),
      });
    } catch (error) {
      return res.status(400).json({
        success: false,
        error: 'Invalid JSON payload',
      });
    }
  }

  res.setHeader('Allow', 'GET,POST,OPTIONS');
  return res.status(405).json({
    success: false,
    error: 'Method not allowed',
  });
};

const state = {
  hasData: false,
  lastPayload: null,
  timer: null,
};

const elements = {
  connectionStatus: document.getElementById('connectionStatus'),
  connectionLabel: document.getElementById('connectionLabel'),
  cpuValue: document.getElementById('cpuValue'),
  ramValue: document.getElementById('ramValue'),
  playersValue: document.getElementById('playersValue'),
  serverValue: document.getElementById('serverValue'),
  timeValue: document.getElementById('timeValue'),
  apiMessage: document.getElementById('apiMessage'),
};

function setConnectionState(stateName, label) {
  elements.connectionStatus.dataset.state = stateName;
  elements.connectionLabel.textContent = label;
}

function markLoading(isLoading) {
  const targets = [
    elements.cpuValue,
    elements.ramValue,
    elements.playersValue,
    elements.serverValue,
    elements.timeValue,
  ];

  targets.forEach((node) => {
    node.classList.toggle('is-loading', isLoading);
  });
}

function renderData(data) {
  if (!data || data.ready === false) {
    state.hasData = false;
    markLoading(true);
    setConnectionState('loading', 'Connecting');
    elements.apiMessage.textContent = 'Waiting for the first server payload...';
    elements.cpuValue.textContent = '--';
    elements.ramValue.textContent = '--';
    elements.playersValue.textContent = '--';
    elements.serverValue.textContent = '--';
    elements.serverValue.className = 'stat-card__value stat-card__value--status';
    elements.timeValue.textContent = '--';
    return;
  }

  state.hasData = true;
  state.lastPayload = data;
  markLoading(false);

  const serverState = String(data.status || 'offline').toLowerCase() === 'online' ? 'online' : 'offline';
  const players = Number.isFinite(Number(data.players)) ? Number(data.players) : 0;

  setConnectionState(serverState === 'online' ? 'online' : 'offline', serverState === 'online' ? 'Online' : 'Offline');

  elements.cpuValue.textContent = data.cpu || '--';
  elements.ramValue.textContent = data.ram || '--';
  elements.playersValue.textContent = String(players);
  elements.serverValue.textContent = serverState;
  elements.serverValue.className = `stat-card__value stat-card__value--status ${serverState}`;
  elements.timeValue.textContent = data.time || '--';
  elements.apiMessage.textContent = 'Auto-refreshing every 2 seconds.';
}

async function fetchStats() {
  try {
    const response = await fetch('/api/data', {
      method: 'GET',
      cache: 'no-store',
      headers: {
        'Accept': 'application/json',
      },
    });

    if (!response.ok) {
      if (!state.hasData) {
        markLoading(true);
        setConnectionState('error', 'API error');
        elements.apiMessage.textContent = `Unable to reach the API yet (HTTP ${response.status}). Retrying automatically...`;
        elements.cpuValue.textContent = '--';
        elements.ramValue.textContent = '--';
        elements.playersValue.textContent = '--';
        elements.serverValue.textContent = 'offline';
        elements.serverValue.className = 'stat-card__value stat-card__value--status offline';
        elements.timeValue.textContent = '--';
        return;
      }

      setConnectionState('error', 'API error');
      elements.apiMessage.textContent = `API request failed (HTTP ${response.status}). Keeping the last known values on screen.`;
      return;
    }

    const payload = await response.json();
    renderData(payload);
  } catch (error) {
    if (!state.hasData) {
      markLoading(true);
      setConnectionState('error', 'API error');
      elements.apiMessage.textContent = 'Unable to reach the API yet. Retrying automatically...';
      elements.cpuValue.textContent = '--';
      elements.ramValue.textContent = '--';
      elements.playersValue.textContent = '--';
      elements.serverValue.textContent = 'offline';
      elements.serverValue.className = 'stat-card__value stat-card__value--status offline';
      elements.timeValue.textContent = '--';
      return;
    }

    setConnectionState('online', 'Live');
    elements.apiMessage.textContent = `Last update kept on screen. Refresh error: ${error.message}`;
  }
}

function startPolling() {
  fetchStats();
  state.timer = window.setInterval(fetchStats, 2000);
}

document.addEventListener('DOMContentLoaded', () => {
  renderData(null);
  startPolling();
});

{
  "name": "dxir-stats",
  "version": "1.0.0",
  "private": true,
  "description": "DXIR STATS — a Vercel-ready live server dashboard and sender script.",
  "main": "api/data.js",
  "scripts": {
    "send": "node sender/send.js"
  },
  "engines": {
    "node": ">=18"
  },
  "dependencies": {
    "axios": "^1.15.0",
    "minecraft-server-util": "^5.0.0",
    "systeminformation": "^5.31.0"
  }
}

const os = require('os');
const axios = require('axios');
const systeminformation = require('systeminformation');
const { status: minecraftStatus } = require('minecraft-server-util');

const rawBaseUrl = process.env.DXIR_STATS_URL || process.env.DXIR_STATS_ENDPOINT || process.env.VERCEL_URL || process.argv[2] || 'https://YOUR-VERCEL-URL';
const endpoint = normalizeEndpoint(rawBaseUrl);

if (endpoint.includes('YOUR-VERCEL-URL')) {
  console.error('Set DXIR_STATS_URL, DXIR_STATS_ENDPOINT, VERCEL_URL, or pass the deployment URL as the first argument.');
  process.exit(1);
}

let sending = false;

function normalizeBaseUrl(value) {
  const trimmed = String(value || '').trim().replace(/\/$/, '');

  if (!trimmed) {
    return trimmed;
  }

  if (/^https?:\/\//i.test(trimmed)) {
    return trimmed;
  }

  return `https://${trimmed}`;
}

function normalizeEndpoint(value) {
  const normalized = normalizeBaseUrl(value);

  if (normalized.toLowerCase().endsWith('/api/data')) {
    return normalized;
  }

  return `${normalized}/api/data`;
}

function formatTimestamp(date = new Date()) {
  return date.toLocaleTimeString([], {
    hour: 'numeric',
    minute: '2-digit',
  });
}

async function getCpuUsage() {
  const load = await systeminformation.currentLoad();
  return `${Math.round(load.currentLoad)}%`;
}

async function getRamUsage() {
  const memory = await systeminformation.mem();
  const totalMb = memory.total / 1024 / 1024;
  const usedMb = memory.active / 1024 / 1024;

  if (totalMb >= 1024) {
    return `${(usedMb / 1024).toFixed(1)} GB / ${(totalMb / 1024).toFixed(1)} GB`;
  }

  return `${Math.round(usedMb)} MB / ${Math.round(totalMb)} MB`;
}

async function getMinecraftStatus() {
  try {
    const result = await minecraftStatus('127.0.0.1', 25565, {
      timeout: 2500,
    });

    return {
      players: Number(result?.players?.online ?? 0),
      status: 'online',
    };
  } catch (error) {
    return {
      players: 0,
      status: 'offline',
    };
  }
}

async function buildPayload() {
  const [cpu, ram, minecraft] = await Promise.all([
    getCpuUsage(),
    getRamUsage(),
    getMinecraftStatus(),
  ]);

  return {
    cpu,
    ram,
    players: minecraft.players,
    status: minecraft.status,
    time: formatTimestamp(),
    host: os.hostname(),
  };
}

async function sendOnce() {
  if (sending) {
    return;
  }

  sending = true;

  try {
    const payload = await buildPayload();
    const response = await axios.post(endpoint, payload, {
      timeout: 5000,
      headers: {
        'Content-Type': 'application/json',
      },
    });

    console.log(`[DXIR STATS] ${payload.status.toUpperCase()} | CPU ${payload.cpu} | RAM ${payload.ram} | Players ${payload.players} | ${response.status}`);
  } catch (error) {
    const message = error?.response
      ? `HTTP ${error.response.status}`
      : error?.message || 'Unknown error';

    console.error(`[DXIR STATS] Failed to send update: ${message}`);
  } finally {
    sending = false;
  }
}

async function main() {
  console.log(`[DXIR STATS] Sending to ${endpoint}`);
  await sendOnce();
  setInterval(sendOnce, 2000);
}

main().catch((error) => {
  console.error('[DXIR STATS] Fatal error:', error);
  process.exit(1);
});

:root {
  color-scheme: dark;
  --bg: #04060f;
  --bg-soft: rgba(8, 12, 24, 0.72);
  --card: rgba(12, 17, 33, 0.68);
  --card-border: rgba(130, 190, 255, 0.18);
  --text: #eef5ff;
  --muted: #8ea2c6;
  --cyan: #57e7ff;
  --blue: #4d7dff;
  --green: #43f1b6;
  --red: #ff6b8b;
  --shadow: 0 24px 60px rgba(0, 0, 0, 0.45);
  --radius: 24px;
  --gap: 20px;
}

* {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  margin: 0;
  min-height: 100vh;
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  color: var(--text);
  background:
    radial-gradient(circle at top left, rgba(69, 133, 255, 0.24), transparent 32%),
    radial-gradient(circle at top right, rgba(87, 231, 255, 0.16), transparent 26%),
    radial-gradient(circle at bottom center, rgba(67, 241, 182, 0.12), transparent 26%),
    linear-gradient(180deg, #04060f 0%, #050814 45%, #02030a 100%);
}

body::before {
  content: "";
  position: fixed;
  inset: 0;
  pointer-events: none;
  background-image:
    linear-gradient(rgba(255, 255, 255, 0.02) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255, 255, 255, 0.02) 1px, transparent 1px);
  background-size: 42px 42px;
  mask-image: linear-gradient(180deg, rgba(0, 0, 0, 0.6), transparent 90%);
  opacity: 0.45;
}

.app-shell {
  width: min(1180px, calc(100vw - 32px));
  margin: 0 auto;
  padding: 28px 0 40px;
}

.glass-card {
  background: linear-gradient(180deg, rgba(17, 24, 45, 0.88), rgba(9, 13, 26, 0.78));
  border: 1px solid var(--card-border);
  box-shadow: var(--shadow);
  backdrop-filter: blur(18px);
  -webkit-backdrop-filter: blur(18px);
}

.hero {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 24px;
  border-radius: var(--radius);
  padding: 24px 26px;
  margin-bottom: 22px;
  animation: fadeUp 700ms ease both;
}

.hero__brand {
  display: flex;
  align-items: center;
  gap: 16px;
}

.logo-mark {
  width: 58px;
  height: 58px;
  border-radius: 18px;
  display: grid;
  place-items: center;
  background: linear-gradient(135deg, rgba(87, 231, 255, 0.2), rgba(77, 125, 255, 0.34));
  border: 1px solid rgba(143, 201, 255, 0.28);
  box-shadow: 0 0 25px rgba(87, 231, 255, 0.25), inset 0 0 20px rgba(87, 231, 255, 0.12);
}

.logo-mark span {
  width: 22px;
  height: 22px;
  border-radius: 7px;
  background: linear-gradient(135deg, var(--cyan), var(--blue));
  box-shadow: 0 0 20px rgba(87, 231, 255, 0.85);
}

.eyebrow {
  margin: 0 0 6px;
  color: var(--cyan);
  text-transform: uppercase;
  letter-spacing: 0.22em;
  font-size: 0.74rem;
  font-weight: 700;
}

.hero h1 {
  margin: 0;
  font-size: clamp(2rem, 4vw, 3.4rem);
  line-height: 1.02;
  letter-spacing: 0.03em;
}

.hero__meta {
  text-align: right;
  max-width: 380px;
}

.hero__subtitle {
  margin: 12px 0 0;
  color: var(--muted);
  font-size: 0.98rem;
  line-height: 1.6;
}

.status-pill {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 10px 14px;
  border-radius: 999px;
  border: 1px solid rgba(143, 201, 255, 0.16);
  background: rgba(6, 10, 24, 0.58);
  color: var(--text);
  font-weight: 600;
  box-shadow: 0 0 18px rgba(87, 231, 255, 0.08);
}

.status-pill__dot {
  width: 10px;
  height: 10px;
  border-radius: 999px;
  background: var(--blue);
  box-shadow: 0 0 16px currentColor;
}

.status-pill[data-state="loading"] .status-pill__dot {
  color: var(--cyan);
  background: var(--cyan);
}

.status-pill[data-state="online"] .status-pill__dot {
  color: var(--green);
  background: var(--green);
}

.status-pill[data-state="offline"] .status-pill__dot,
.status-pill[data-state="error"] .status-pill__dot {
  color: var(--red);
  background: var(--red);
}

.dashboard-grid {
  display: grid;
  grid-template-columns: repeat(12, 1fr);
  gap: var(--gap);
}

.stat-card {
  grid-column: span 6;
  border-radius: var(--radius);
  padding: 22px 22px 20px;
  position: relative;
  overflow: hidden;
  transform: translateY(0);
  transition: transform 180ms ease, border-color 180ms ease, box-shadow 180ms ease;
  animation: fadeUp 700ms ease both;
}

.stat-card:nth-child(1) { animation-delay: 80ms; }
.stat-card:nth-child(2) { animation-delay: 140ms; }
.stat-card:nth-child(3) { animation-delay: 200ms; }
.stat-card:nth-child(4) { animation-delay: 260ms; }
.stat-card:nth-child(5) { animation-delay: 320ms; }

.stat-card::after {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, rgba(255, 255, 255, 0.04), transparent 40%);
  pointer-events: none;
}

.stat-card:hover {
  transform: translateY(-4px);
  border-color: rgba(87, 231, 255, 0.36);
  box-shadow: 0 26px 64px rgba(0, 0, 0, 0.56), 0 0 30px rgba(77, 125, 255, 0.16);
}

.stat-card--wide {
  grid-column: span 12;
}

.stat-card__header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 14px;
  margin-bottom: 18px;
}

.stat-card__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 74px;
  padding: 8px 12px;
  border-radius: 999px;
  font-size: 0.76rem;
  font-weight: 800;
  letter-spacing: 0.12em;
  color: #07111d;
  background: linear-gradient(135deg, rgba(87, 231, 255, 0.96), rgba(77, 125, 255, 0.92));
  box-shadow: 0 0 20px rgba(87, 231, 255, 0.34);
}

.stat-card__label {
  color: var(--muted);
  font-size: 0.88rem;
  font-weight: 600;
  text-align: right;
}

.stat-card__value {
  font-size: clamp(2rem, 5vw, 3.65rem);
  font-weight: 800;
  letter-spacing: -0.04em;
  line-height: 1.05;
  text-shadow: 0 0 22px rgba(87, 231, 255, 0.15);
}

.stat-card__value--status {
  text-transform: capitalize;
}

.stat-card__value--time {
  font-size: clamp(1.7rem, 4vw, 2.7rem);
}

.stat-card__footer {
  margin-top: 12px;
  color: var(--muted);
  font-size: 0.92rem;
  line-height: 1.5;
}

.stat-card--accent .stat-card__value,
.stat-card--accent-2 .stat-card__value,
.stat-card--accent-3 .stat-card__value,
.stat-card--accent-4 .stat-card__value {
  background: linear-gradient(135deg, #ffffff, #7fdcff 45%, #4d7dff 100%);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
}

.stat-card--accent-4 .stat-card__value--status.online {
  background: linear-gradient(135deg, #d9fff0, #43f1b6 50%, #2fb47e);
  -webkit-background-clip: text;
  background-clip: text;
}

.stat-card--accent-4 .stat-card__value--status.offline {
  background: linear-gradient(135deg, #fff1f5, #ff6b8b 55%, #ff9ab1);
  -webkit-background-clip: text;
  background-clip: text;
}

.is-loading {
  position: relative;
  display: inline-block;
  min-height: 1.1em;
  color: transparent !important;
  border-radius: 10px;
  background: linear-gradient(90deg, rgba(128, 153, 188, 0.14), rgba(128, 153, 188, 0.28), rgba(128, 153, 188, 0.14));
  background-size: 200% 100%;
  animation: shimmer 1.3s linear infinite;
}

.is-loading::before {
  content: "\00a0";
}

@keyframes shimmer {
  0% { background-position: 200% 0; }
  100% { background-position: -200% 0; }
}

@keyframes fadeUp {
  from {
    opacity: 0;
    transform: translateY(14px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@media (max-width: 880px) {
  .hero {
    flex-direction: column;
    align-items: flex-start;
  }

  .hero__meta {
    width: 100%;
    text-align: left;
  }

  .stat-card {
    grid-column: span 12;
  }
}

@media (max-width: 560px) {
  .app-shell {
    width: min(100vw - 20px, 1180px);
    padding-top: 14px;
  }

  .hero,
  .stat-card {
    padding-left: 18px;
    padding-right: 18px;
  }

  .hero h1 {
    font-size: clamp(1.8rem, 11vw, 2.6rem);
  }

  .stat-card__header {
    align-items: flex-start;
    flex-direction: column;
  }

  .stat-card__label {
    text-align: left;
  }

  .stat-card__value {
    font-size: clamp(1.8rem, 10vw, 3rem);
  }

  .stat-card__value--time {
    font-size: clamp(1.5rem, 8vw, 2.3rem);
  }
}
